# OEIS sequence: A126216

# with a left unit column adjoined and (0, 0)-based.
def A126216row(n: int) -> list[int]:
    if n == 0: return [1]
    row = [0] * (n + 1)
    row[n] = 1
    for m in range(n, 1, -1):
        num = (m - 1) * (2 * n - m + 2)
        den = (n - m + 2) * (n - m + 1)
        row[m - 1] = (row[m] * num) // den
    return row
